class CustomMOEA:
    """SDE-NSGA-II: Non-dominated Sorting with Shift-Based Density Estimation."""

    def __init__(
        self,
        pop_size: int,
        n_obj: int,
        n_var: int,
        bounds: Tuple[float, float],
        cx_eta: float = 20.0,
        mut_eta: float = 20.0,
        mut_prob: Optional[float] = None,
    ):
        self.pop_size = pop_size
        self.n_obj = n_obj
        self.n_var = n_var
        self.bounds = bounds
        self.cx_eta = cx_eta
        self.mut_eta = mut_eta
        self.mut_prob = mut_prob if mut_prob is not None else 1.0 / n_var

    def select(self, population: list, k: int) -> list:
        """Tournament selection using rank and SDE distances."""
        selected = []
        for _ in range(k):
            i1, i2 = random.sample(range(len(population)), 2)
            a, b = population[i1], population[i2]

            rank_a = getattr(a, '_rank', 0)
            rank_b = getattr(b, '_rank', 0)

            if rank_a < rank_b:
                selected.append(deepcopy(a))
            elif rank_b < rank_a:
                selected.append(deepcopy(b))
            else:
                cd_a = getattr(a.fitness, 'crowding_dist', 0)
                cd_b = getattr(b.fitness, 'crowding_dist', 0)
                if cd_a > cd_b:
                    selected.append(deepcopy(a))
                elif cd_b > cd_a:
                    selected.append(deepcopy(b))
                else:
                    selected.append(deepcopy(random.choice([a, b])))
        return selected

    def vary(self, parents: list) -> list:
        offspring = [deepcopy(p) for p in parents]
        lo, hi = self.bounds
        n = len(offspring)

        # Mix SBX and Differential Evolution (DE)
        for i in range(0, n - 1, 2):
            if random.random() < 0.5:
                # SBX Crossover
                tools.cxSimulatedBinaryBounded(offspring[i], offspring[i+1], eta=self.cx_eta, low=lo, up=hi)
                try:
                    del offspring[i].fitness.values
                    del offspring[i+1].fitness.values
                except AttributeError:
                    pass
            else:
                # DE Crossover for both children
                for child_idx in (i, i+1):
                    r1, r2, r3 = random.sample(range(n), 3)
                    j_rand = random.randint(0, self.n_var - 1)
                    for j in range(self.n_var):
                        if random.random() < 0.9 or j == j_rand:
                            val = parents[r1][j] + 0.5 * (parents[r2][j] - parents[r3][j])
                            offspring[child_idx][j] = max(lo, min(hi, val))
                    try:
                        del offspring[child_idx].fitness.values
                    except AttributeError:
                        pass

        # Polynomial Mutation
        for ind in offspring:
            if random.random() < 1.0:
                tools.mutPolynomialBounded(ind, eta=self.mut_eta, low=lo, up=hi, indpb=self.mut_prob)
                try:
                    del ind.fitness.values
                except AttributeError:
                    pass

        return offspring

    def survive(self, population: list, offspring: list) -> list:
        combined = population + offspring
        fronts = tools.sortNondominated(combined, self.pop_size, first_front_only=False)

        next_gen = []
        for rank, front in enumerate(fronts):
            for ind in front:
                ind._rank = rank

            if len(next_gen) + len(front) <= self.pop_size:
                self._assign_sde_crowding(front)
                next_gen.extend(front)
            else:
                remaining = self.pop_size - len(next_gen)
                truncated_front = self._sde_truncation(front, remaining)
                self._assign_sde_crowding(truncated_front)
                next_gen.extend(truncated_front)
                break

        return next_gen

    def _sde_truncation(self, front, k):
        F = np.array([ind.fitness.values for ind in front])
        n = len(front)

        z_min = F.min(axis=0)
        z_max = F.max(axis=0)
        scale = np.clip(z_max - z_min, 1e-12, None)
        F_norm = (F - z_min) / scale

        sde_mat = np.zeros((n, n))
        for i in range(n):
            for j in range(n):
                if i != j:
                    diff = np.maximum(0, F_norm[j] - F_norm[i])
                    sde_mat[i, j] = np.sqrt(np.sum(diff**2))
                else:
                    sde_mat[i, j] = np.inf

        active = list(range(n))
        while len(active) > k:
            sorted_dists = []
            for i in active:
                dists = [sde_mat[i, j] for j in active if j != i]
                dists.sort()
                sorted_dists.append(dists)

            worst_idx = 0
            for i in range(1, len(active)):
                for d_i, d_worst in zip(sorted_dists[i], sorted_dists[worst_idx]):
                    if abs(d_i - d_worst) > 1e-12:
                        if d_i < d_worst:
                            worst_idx = i
                        break
            active.pop(worst_idx)

        return [front[i] for i in active]

    def _assign_sde_crowding(self, front):
        if len(front) <= 2:
            for ind in front:
                ind.fitness.crowding_dist = float('inf')
            return

        F = np.array([ind.fitness.values for ind in front])
        n = len(front)
        z_min = F.min(axis=0)
        z_max = F.max(axis=0)
        scale = np.clip(z_max - z_min, 1e-12, None)
        F_norm = (F - z_min) / scale

        for i in range(n):
            min_dist = float('inf')
            for j in range(n):
                if i != j:
                    diff = np.maximum(0, F_norm[j] - F_norm[i])
                    d = np.sum(diff**2)
                    if d < min_dist:
                        min_dist = d
            front[i].fitness.crowding_dist = np.sqrt(min_dist)

    def on_generation(self, gen: int, population: list):
        pass

def survive(self, population: list, offspring: list) -> list:
    combined = population + offspring
    fronts = tools.sortNondominated(combined, self.pop_size, first_front_only=False)

    F_all = np.array([ind.fitness.values for ind in combined])
    z_min = F_all.min(axis=0)
    z_max = F_all.max(axis=0)
    scale = np.clip(z_max - z_min, 1e-12, None)

    next_gen = []
    for rank, front in enumerate(fronts):
        for ind in front:
            ind._rank = rank

        if len(next_gen) + len(front) <= self.pop_size:
            self._assign_sde_crowding(front, z_min, scale)
            next_gen.extend(front)
        else:
            remaining = self.pop_size - len(next_gen)
            truncated_front = self._sde_truncation(front, remaining, z_min, scale)
            self._assign_sde_crowding(truncated_front, z_min, scale)
            next_gen.extend(truncated_front)
            break

    return next_gen

def _sde_truncation(self, front, k, z_min, scale):
    F = np.array([ind.fitness.values for ind in front])
    n = len(front)

    F_norm = (F - z_min) / scale

    sde_mat = np.zeros((n, n))
    for i in range(n):
        for j in range(n):
            if i != j:
                diff = np.maximum(0, F_norm[j] - F_norm[i])
                sde_mat[i, j] = np.sqrt(np.sum(diff**2))
            else:
                sde_mat[i, j] = np.inf

    active = list(range(n))
    while len(active) > k:
        sorted_dists = []
        for i in active:
            dists = [sde_mat[i, j] for j in active if j != i]
            dists.sort()
            sorted_dists.append(dists)

        worst_idx = 0
        for i in range(1, len(active)):
            for d_i, d_worst in zip(sorted_dists[i], sorted_dists[worst_idx]):
                if abs(d_i - d_worst) > 1e-12:
                    if d_i < d_worst:
                        worst_idx = i
                    break
        active.pop(worst_idx)

    return [front[i] for i in active]

def _assign_sde_crowding(self, front, z_min, scale):
    if len(front) <= 2:
        for ind in front:
            ind.fitness.crowding_dist = float('inf')
        return

    F = np.array([ind.fitness.values for ind in front])
    n = len(front)
    F_norm = (F - z_min) / scale

    for i in range(n):
        min_dist = float('inf')
        for j in range(n):
            if i != j:
                diff = np.maximum(0, F_norm[j] - F_norm[i])
                d = np.sum(diff**2)
                if d < min_dist:
                    min_dist = d
        front[i].fitness.crowding_dist = np.sqrt(min_dist)

def select(self, population: list, k: int) -> list:
    fronts = tools.sortNondominated(population, len(population), first_front_only=False)
    for front in fronts:
        compute_crowding_distance(front)
    return tools.selTournamentDCD(population, k)

def vary(self, parents: list) -> list:
    offspring = []
    lo, hi = self.bounds
    for i in range(len(parents)):
        child = deepcopy(parents[i])
        if random.random() < 0.5:
            # DE variation
            r1, r2, r3 = random.sample(parents, 3)
            F_weight = random.uniform(0.4, 0.8)
            CR = random.uniform(0.7, 1.0)
            j_rand = random.randint(0, self.n_var - 1)
            for j in range(self.n_var):
                if random.random() < CR or j == j_rand:
                    child[j] = r1[j] + F_weight * (r2[j] - r3[j])
                    if child[j] < lo: child[j] = lo
                    if child[j] > hi: child[j] = hi
        else:
            # SBX
            mate_idx = random.randint(0, len(parents) - 1)
            tools.cxSimulatedBinaryBounded(child, parents[mate_idx], eta=self.cx_eta, low=lo, up=hi)

        if random.random() < 1.0:
            tools.mutPolynomialBounded(child, eta=self.mut_eta, low=lo, up=hi, indpb=self.mut_prob)
        del child.fitness.values
        offspring.append(child)
    return offspring

def survive(self, population: list, offspring: list) -> list:
    combined = population + offspring
    fronts = tools.sortNondominated(combined, self.pop_size, first_front_only=False)

    next_gen = []
    for front in fronts:
        if len(next_gen) + len(front) <= self.pop_size:
            next_gen.extend(front)
        else:
            remaining = self.pop_size - len(next_gen)
            F_front = np.array([ind.fitness.values for ind in front])

            z_min = np.min(F_front, axis=0)
            z_max = np.max(F_front, axis=0)
            scale = z_max - z_min
            scale[scale < 1e-12] = 1.0
            F_front_norm = (F_front - z_min) / scale

            selected_indices = []
            min_dists = np.full(len(front), np.inf)

            if len(next_gen) > 0:
                F_next = np.array([ind.fitness.values for ind in next_gen])
                F_next_norm = (F_next - z_min) / scale
                for i in range(len(front)):
                    diffs = F_next_norm - F_front_norm[i]
                    dists = np.sum(diffs**2, axis=1)
                    if len(dists) > 0:
                        min_dists[i] = np.min(dists)
            else:
                for m in range(self.n_obj):
                    if len(selected_indices) >= remaining:
                        break
                    idx = np.argmin(F_front_norm[:, m])
                    if idx not in selected_indices:
                        selected_indices.append(idx)
                        diffs = F_front_norm - F_front_norm[idx]
                        min_dists = np.minimum(min_dists, np.sum(diffs**2, axis=1))

            while len(selected_indices) < remaining:
                masked_dists = min_dists.copy()
                masked_dists[selected_indices] = -1.0 

                best_idx = int(np.argmax(masked_dists))
                selected_indices.append(best_idx)

                diffs = F_front_norm - F_front_norm[best_idx]
                min_dists = np.minimum(min_dists, np.sum(diffs**2, axis=1))

            next_gen.extend([front[i] for i in selected_indices])
            break

    return next_gen

def on_generation(self, gen: int, population: list):
    pass
